class Solution {
public:
    int lengthAfterTransformations(string s, int t, vector<int>& nums) {
        int n = s.size();
        int mod = 1e9 + 7;
        string res = s;
        for (int i = 0; i < t; i++) {
            string temp = "";
            for (char c : res) {
                int idx = c - 'a';
                int shift = nums[idx];
                int new_idx = (idx + shift) % 26;
                temp += 'a' + new_idx;
            }
            res = temp;
        }
        return res.size() % mod;
    }
};
```

